import numpy as np

def predict(frame, action):
    out = frame.copy()
    # Observed rule (action 6): a run of color 4 in row 0 grows leftward,
    # one cell per step, starting from the right edge (col 63) toward col 0.
    if action == 6:
        row = out[0]
        cols4 = np.where(row == 4)[0]
        if cols4.size == 0:
            # nothing painted yet -> start at the right edge
            out[0, 63] = 4
        else:
            left = int(cols4.min())
            if left > 0:
                out[0, left - 1] = 4
    return out
